contracts/AllinToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

/**
 * 测试用 ALLIN 代币：ERC20 + 铸造 + 金库燃烧（仅 BurnRouter 可调）
 */
contract AllinToken {
    string public name = "ALLIN Test";
    string public symbol = "ALLIN";
    uint8 public decimals = 18;

    address public owner;
    address public burnRouter;

    mapping(address => uint256) private _balances;
    mapping(address => mapping(address => uint256)) private _allowances;
    uint256 private _totalSupply;

    event Transfer(address indexed from, address indexed to, uint256 value);
    event Approval(address indexed owner, address indexed spender, uint256 value);
    event BurnRouterUpdated(address indexed previousRouter, address indexed newRouter);

    modifier onlyOwner() {
        require(msg.sender == owner, "ONLY_OWNER");
        _;
    }

    constructor(uint256 initialSupply) {
        owner = msg.sender;
        if (initialSupply > 0) {
            _mint(msg.sender, initialSupply);
        }
    }

    function totalSupply() external view returns (uint256) {
        return _totalSupply;
    }

    function balanceOf(address account) external view returns (uint256) {
        return _balances[account];
    }

    function transfer(address to, uint256 amount) external returns (bool) {
        _transfer(msg.sender, to, amount);
        return true;
    }

    function allowance(address from, address spender) external view returns (uint256) {
        return _allowances[from][spender];
    }

    function approve(address spender, uint256 amount) external returns (bool) {
        _allowances[msg.sender][spender] = amount;
        emit Approval(msg.sender, spender, amount);
        return true;
    }

    function transferFrom(address from, address to, uint256 amount) external returns (bool) {
        uint256 currentAllowance = _allowances[from][msg.sender];
        if (currentAllowance != type(uint256).max) {
            require(currentAllowance >= amount, "ALLOWANCE_EXCEEDED");
            _allowances[from][msg.sender] = currentAllowance - amount;
        }
        _transfer(from, to, amount);
        return true;
    }

    function setBurnRouter(address newBurnRouter) external onlyOwner {
        address previous = burnRouter;
        burnRouter = newBurnRouter;
        emit BurnRouterUpdated(previous, newBurnRouter);
    }

    /// @notice 仅 BurnRouter 可调：从指定账户（金库）销毁代币
    function burnFromVault(address vaultAccount, uint256 value) external {
        require(msg.sender == burnRouter, "ONLY_BURN_ROUTER");
        _burn(vaultAccount, value);
    }

    /// @notice 测试用：仅 owner 可铸造
    function mint(address to, uint256 amount) external onlyOwner {
        _mint(to, amount);
    }

    function _transfer(address from, address to, uint256 amount) internal {
        require(from != address(0), "FROM_ZERO");
        require(to != address(0), "TO_ZERO");
        require(_balances[from] >= amount, "INSUFFICIENT_BALANCE");
        _balances[from] -= amount;
        _balances[to] += amount;
        emit Transfer(from, to, amount);
    }

    function _mint(address to, uint256 amount) internal {
        require(to != address(0), "MINT_TO_ZERO");
        _totalSupply += amount;
        _balances[to] += amount;
        emit Transfer(address(0), to, amount);
    }

    function _burn(address account, uint256 amount) internal {
        require(account != address(0), "BURN_FROM_ZERO");
        require(_balances[account] >= amount, "INSUFFICIENT_BALANCE");
        _balances[account] -= amount;
        _totalSupply -= amount;
        emit Transfer(account, address(0), amount);
    }
}

contracts/BurnRouter.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

interface IAllinBurnRouterToken {
    function burnFromVault(address vaultAccount, uint256 value) external;
}

contract BurnRouter {
    enum ActionType {
        Unknown,
        RoomCreation,
        TournamentRegistration,
        CashGameRake,
        ManualAdjustment
    }

    struct BurnAction {
        bytes32 actionId;
        ActionType actionType;
        address user;
        address treasuryAccount;
        uint256 amount;
        string referenceId;
        bytes32 metadataHash;
        uint256 burnedAt;
    }

    address public owner;
    address public treasuryAccount;
    IAllinBurnRouterToken public immutable token;
    bool public paused;

    BurnAction[] public burnActions;
    mapping(address => bool) public operators;
    mapping(address => bool) public pausers;
    mapping(bytes32 => bool) public processedActionIds;

    event OwnerUpdated(address indexed previousOwner, address indexed newOwner);
    event TreasuryAccountUpdated(address indexed previousTreasuryAccount, address indexed newTreasuryAccount);
    event OperatorUpdated(address indexed account, bool allowed);
    event PauserUpdated(address indexed account, bool allowed);
    event Paused(address indexed account);
    event Unpaused(address indexed account);
    event BurnExecuted(
        bytes32 indexed actionId,
        uint8 indexed actionType,
        address indexed user,
        address treasuryAccount,
        uint256 amount,
        string referenceId,
        bytes32 metadataHash
    );

    modifier onlyOwner() {
        require(msg.sender == owner, "ONLY_OWNER");
        _;
    }

    modifier onlyOperator() {
        require(msg.sender == owner || operators[msg.sender], "ONLY_OPERATOR");
        _;
    }

    modifier onlyPauser() {
        require(msg.sender == owner || pausers[msg.sender], "ONLY_PAUSER");
        _;
    }

    modifier whenNotPaused() {
        require(!paused, "BURN_ROUTER_PAUSED");
        _;
    }

    constructor(address initialOwner, address tokenAddress, address initialTreasuryAccount) {
        require(initialOwner != address(0), "INVALID_OWNER");
        require(tokenAddress != address(0), "INVALID_TOKEN");
        require(initialTreasuryAccount != address(0), "INVALID_TREASURY");

        owner = initialOwner;
        token = IAllinBurnRouterToken(tokenAddress);
        treasuryAccount = initialTreasuryAccount;
        operators[initialOwner] = true;
        pausers[initialOwner] = true;

        emit OperatorUpdated(initialOwner, true);
        emit PauserUpdated(initialOwner, true);
    }

    function setOwner(address newOwner) external onlyOwner {
        require(newOwner != address(0), "INVALID_OWNER");
        emit OwnerUpdated(owner, newOwner);
        owner = newOwner;
    }

    function setTreasuryAccount(address newTreasuryAccount) external onlyOwner {
        require(newTreasuryAccount != address(0), "INVALID_TREASURY");
        emit TreasuryAccountUpdated(treasuryAccount, newTreasuryAccount);
        treasuryAccount = newTreasuryAccount;
    }

    function setOperator(address account, bool allowed) external onlyOwner {
        operators[account] = allowed;
        emit OperatorUpdated(account, allowed);
    }

    function setPauser(address account, bool allowed) external onlyOwner {
        pausers[account] = allowed;
        emit PauserUpdated(account, allowed);
    }

    function pause() external onlyPauser {
        paused = true;
        emit Paused(msg.sender);
    }

    function unpause() external onlyPauser {
        paused = false;
        emit Unpaused(msg.sender);
    }

    function burnForRoomCreation(
        bytes32 actionId,
        address user,
        uint256 amount,
        string calldata referenceId,
        bytes32 metadataHash
    ) external onlyOperator whenNotPaused {
        _burn(actionId, ActionType.RoomCreation, user, amount, referenceId, metadataHash);
    }

    function burnForTournament(
        bytes32 actionId,
        address user,
        uint256 amount,
        string calldata referenceId,
        bytes32 metadataHash
    ) external onlyOperator whenNotPaused {
        _burn(actionId, ActionType.TournamentRegistration, user, amount, referenceId, metadataHash);
    }

    function burnForCashGameRake(
        bytes32 actionId,
        address user,
        uint256 amount,
        string calldata referenceId,
        bytes32 metadataHash
    ) external onlyOperator whenNotPaused {
        _burn(actionId, ActionType.CashGameRake, user, amount, referenceId, metadataHash);
    }

    function burnManual(
        bytes32 actionId,
        address user,
        uint256 amount,
        string calldata referenceId,
        bytes32 metadataHash
    ) external onlyOperator whenNotPaused {
        _burn(actionId, ActionType.ManualAdjustment, user, amount, referenceId, metadataHash);
    }

    function getBurnActionCount() external view returns (uint256) {
        return burnActions.length;
    }

    function _burn(
        bytes32 actionId,
        ActionType actionType,
        address user,
        uint256 amount,
        string calldata referenceId,
        bytes32 metadataHash
    ) internal {
        require(actionId != bytes32(0), "INVALID_ACTION_ID");
        require(!processedActionIds[actionId], "ACTION_ALREADY_PROCESSED");
        require(user != address(0), "INVALID_USER");
        require(amount > 0, "INVALID_AMOUNT");

        processedActionIds[actionId] = true;
        token.burnFromVault(treasuryAccount, amount);

        burnActions.push(
            BurnAction({
                actionId: actionId,
                actionType: actionType,
                user: user,
                treasuryAccount: treasuryAccount,
                amount: amount,
                referenceId: referenceId,
                metadataHash: metadataHash,
                burnedAt: block.timestamp
            })
        );

        emit BurnExecuted(
            actionId,
            uint8(actionType),
            user,
            treasuryAccount,
            amount,
            referenceId,
            metadataHash
        );
    }
}

contracts/GameTreasuryVault.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

interface IGameTreasuryToken {
    function transferFrom(address from, address to, uint256 value) external returns (bool);
    function transfer(address to, uint256 value) external returns (bool);
    function balanceOf(address account) external view returns (uint256);
}

interface IRecoverableToken {
    function transfer(address to, uint256 value) external returns (bool);
}

contract GameTreasuryVault {
    address public owner;
    IGameTreasuryToken public immutable token;
    bool public paused;

    uint256 public totalDeposited;
    uint256 public totalWithdrawn;

    mapping(address => bool) public operators;
    mapping(address => bool) public pausers;
    mapping(bytes32 => bool) public usedDepositIds;
    mapping(bytes32 => bool) public usedWithdrawalIds;
    mapping(address => uint256) public depositedByAccount;
    mapping(address => uint256) public withdrawnByAccount;

    event OwnerUpdated(address indexed previousOwner, address indexed newOwner);
    event OperatorUpdated(address indexed account, bool allowed);
    event PauserUpdated(address indexed account, bool allowed);
    event Paused(address indexed account);
    event Unpaused(address indexed account);
    event Deposited(address indexed depositor, uint256 amount, bytes32 indexed depositId, uint256 vaultBalanceAfter);
    event Withdrawn(address indexed recipient, uint256 amount, bytes32 indexed withdrawalId, uint256 vaultBalanceAfter);
    event EmergencyTokenWithdrawn(address indexed token, address indexed recipient, uint256 amount);
    event EmergencyNativeWithdrawn(address indexed recipient, uint256 amount);

    modifier onlyOwner() {
        require(msg.sender == owner, "ONLY_OWNER");
        _;
    }

    modifier onlyOperator() {
        require(msg.sender == owner || operators[msg.sender], "ONLY_OPERATOR");
        _;
    }

    modifier onlyPauser() {
        require(msg.sender == owner || pausers[msg.sender], "ONLY_PAUSER");
        _;
    }

    modifier whenNotPaused() {
        require(!paused, "VAULT_PAUSED");
        _;
    }

    modifier whenPaused() {
        require(paused, "VAULT_NOT_PAUSED");
        _;
    }

    constructor(address initialOwner, address tokenAddress) {
        require(initialOwner != address(0), "INVALID_OWNER");
        require(tokenAddress != address(0), "INVALID_TOKEN");

        owner = initialOwner;
        token = IGameTreasuryToken(tokenAddress);
        operators[initialOwner] = true;
        pausers[initialOwner] = true;

        emit OperatorUpdated(initialOwner, true);
        emit PauserUpdated(initialOwner, true);
    }

    receive() external payable {}

    function setOwner(address newOwner) external onlyOwner {
        require(newOwner != address(0), "INVALID_OWNER");
        emit OwnerUpdated(owner, newOwner);
        owner = newOwner;
    }

    function setOperator(address account, bool allowed) external onlyOwner {
        operators[account] = allowed;
        emit OperatorUpdated(account, allowed);
    }

    function setPauser(address account, bool allowed) external onlyOwner {
        pausers[account] = allowed;
        emit PauserUpdated(account, allowed);
    }

    function pause() external onlyPauser {
        paused = true;
        emit Paused(msg.sender);
    }

    function unpause() external onlyPauser {
        paused = false;
        emit Unpaused(msg.sender);
    }

    function deposit(uint256 amount, bytes32 depositId) external whenNotPaused {
        require(amount > 0, "INVALID_AMOUNT");
        require(depositId != bytes32(0), "INVALID_DEPOSIT_ID");
        require(!usedDepositIds[depositId], "DEPOSIT_ALREADY_USED");

        usedDepositIds[depositId] = true;
        bool success = token.transferFrom(msg.sender, address(this), amount);
        require(success, "TRANSFER_FROM_FAILED");

        totalDeposited += amount;
        depositedByAccount[msg.sender] += amount;

        emit Deposited(msg.sender, amount, depositId, token.balanceOf(address(this)));
    }

    function withdraw(address recipient, uint256 amount, bytes32 withdrawalId) external onlyOperator whenNotPaused {
        require(recipient != address(0), "INVALID_RECIPIENT");
        require(amount > 0, "INVALID_AMOUNT");
        require(withdrawalId != bytes32(0), "INVALID_WITHDRAWAL_ID");
        require(!usedWithdrawalIds[withdrawalId], "WITHDRAWAL_ALREADY_USED");

        usedWithdrawalIds[withdrawalId] = true;
        bool success = token.transfer(recipient, amount);
        require(success, "TRANSFER_FAILED");

        totalWithdrawn += amount;
        withdrawnByAccount[recipient] += amount;

        emit Withdrawn(recipient, amount, withdrawalId, token.balanceOf(address(this)));
    }

    function vaultBalance() external view returns (uint256) {
        return token.balanceOf(address(this));
    }

    function emergencyWithdrawPrincipalToken(address recipient, uint256 amount) external onlyOwner whenPaused {
        require(recipient != address(0), "INVALID_RECIPIENT");
        require(amount > 0, "INVALID_AMOUNT");

        bool success = token.transfer(recipient, amount);
        require(success, "TRANSFER_FAILED");

        emit EmergencyTokenWithdrawn(address(token), recipient, amount);
    }

    function emergencyWithdrawUnexpectedToken(address tokenAddress, address recipient, uint256 amount)
        external
        onlyOwner
        whenPaused
    {
        require(tokenAddress != address(0), "INVALID_TOKEN");
        require(tokenAddress != address(token), "USE_PRINCIPAL_WITHDRAW");
        require(recipient != address(0), "INVALID_RECIPIENT");
        require(amount > 0, "INVALID_AMOUNT");

        bool success = IRecoverableToken(tokenAddress).transfer(recipient, amount);
        require(success, "TRANSFER_FAILED");

        emit EmergencyTokenWithdrawn(tokenAddress, recipient, amount);
    }

    function emergencyWithdrawNative(address payable recipient, uint256 amount) external onlyOwner whenPaused {
        require(recipient != address(0), "INVALID_RECIPIENT");
        require(amount > 0, "INVALID_AMOUNT");
        require(address(this).balance >= amount, "INSUFFICIENT_NATIVE_BALANCE");

        (bool success,) = recipient.call{value: amount}("");
        require(success, "NATIVE_TRANSFER_FAILED");

        emit EmergencyNativeWithdrawn(recipient, amount);
    }
}

contracts/PrizePoolVault.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

interface IPrizePoolRecoverableToken {
    function transfer(address to, uint256 value) external returns (bool);
}

contract PrizePoolVault {
    struct TournamentPayout {
        bytes32 payoutId;
        bytes32 tournamentId;
        address winner;
        uint256 amount;
        uint256 paidAt;
    }

    address public owner;
    bool public paused;
    uint256 public totalPaid;

    TournamentPayout[] public payouts;
    mapping(address => bool) public payoutOperators;
    mapping(address => bool) public pausers;
    mapping(bytes32 => bool) public usedPayoutIds;

    event OwnerUpdated(address indexed previousOwner, address indexed newOwner);
    event PayoutOperatorUpdated(address indexed account, bool allowed);
    event PauserUpdated(address indexed account, bool allowed);
    event Paused(address indexed account);
    event Unpaused(address indexed account);
    event PrizeDeposited(address indexed sender, uint256 amount, uint256 balanceAfter);
    event PrizePaid(
        bytes32 indexed tournamentId,
        bytes32 indexed payoutId,
        address indexed winner,
        uint256 amount
    );
    event EmergencyNativeWithdrawn(address indexed recipient, uint256 amount);
    event EmergencyTokenWithdrawn(address indexed token, address indexed recipient, uint256 amount);

    modifier onlyOwner() {
        require(msg.sender == owner, "ONLY_OWNER");
        _;
    }

    modifier onlyPayoutOperator() {
        require(msg.sender == owner || payoutOperators[msg.sender], "ONLY_PAYOUT_OPERATOR");
        _;
    }

    modifier onlyPauser() {
        require(msg.sender == owner || pausers[msg.sender], "ONLY_PAUSER");
        _;
    }

    modifier whenNotPaused() {
        require(!paused, "PRIZE_POOL_PAUSED");
        _;
    }

    modifier whenPaused() {
        require(paused, "PRIZE_POOL_NOT_PAUSED");
        _;
    }

    constructor(address initialOwner) {
        require(initialOwner != address(0), "INVALID_OWNER");
        owner = initialOwner;
        payoutOperators[initialOwner] = true;
        pausers[initialOwner] = true;
        emit PayoutOperatorUpdated(initialOwner, true);
        emit PauserUpdated(initialOwner, true);
    }

    receive() external payable {
        emit PrizeDeposited(msg.sender, msg.value, address(this).balance);
    }

    function setOwner(address newOwner) external onlyOwner {
        require(newOwner != address(0), "INVALID_OWNER");
        emit OwnerUpdated(owner, newOwner);
        owner = newOwner;
    }

    function setPayoutOperator(address account, bool allowed) external onlyOwner {
        payoutOperators[account] = allowed;
        emit PayoutOperatorUpdated(account, allowed);
    }

    function setPauser(address account, bool allowed) external onlyOwner {
        pausers[account] = allowed;
        emit PauserUpdated(account, allowed);
    }

    function pause() external onlyPauser {
        paused = true;
        emit Paused(msg.sender);
    }

    function unpause() external onlyPauser {
        paused = false;
        emit Unpaused(msg.sender);
    }

    function payTournamentPrize(
        bytes32 tournamentId,
        bytes32 payoutId,
        address payable winner,
        uint256 amount
    ) external onlyPayoutOperator whenNotPaused {
        _payTournamentPrize(tournamentId, payoutId, winner, amount);
    }

    function payTournamentPrizes(
        bytes32 tournamentId,
        bytes32[] calldata payoutIds,
        address payable[] calldata winners,
        uint256[] calldata amounts
    ) external onlyPayoutOperator whenNotPaused {
        uint256 length = payoutIds.length;
        require(length == winners.length && length == amounts.length, "ARRAY_LENGTH_MISMATCH");

        for (uint256 index = 0; index < length; index++) {
            _payTournamentPrize(tournamentId, payoutIds[index], winners[index], amounts[index]);
        }
    }

    function getPayoutCount() external view returns (uint256) {
        return payouts.length;
    }

    function emergencyWithdrawNative(address payable recipient, uint256 amount)
        external
        onlyOwner
        whenPaused
    {
        require(recipient != address(0), "INVALID_RECIPIENT");
        require(amount > 0, "INVALID_AMOUNT");
        require(address(this).balance >= amount, "INSUFFICIENT_POOL_BALANCE");

        (bool success,) = recipient.call{value: amount}("");
        require(success, "TRANSFER_FAILED");

        emit EmergencyNativeWithdrawn(recipient, amount);
    }

    function emergencyWithdrawUnexpectedToken(address token, address recipient, uint256 amount)
        external
        onlyOwner
        whenPaused
    {
        require(token != address(0), "INVALID_TOKEN");
        require(recipient != address(0), "INVALID_RECIPIENT");
        require(amount > 0, "INVALID_AMOUNT");

        bool success = IPrizePoolRecoverableToken(token).transfer(recipient, amount);
        require(success, "TRANSFER_FAILED");

        emit EmergencyTokenWithdrawn(token, recipient, amount);
    }

    function _payTournamentPrize(
        bytes32 tournamentId,
        bytes32 payoutId,
        address payable winner,
        uint256 amount
    ) internal {
        require(tournamentId != bytes32(0), "INVALID_TOURNAMENT");
        require(payoutId != bytes32(0), "INVALID_PAYOUT_ID");
        require(!usedPayoutIds[payoutId], "PAYOUT_ALREADY_USED");
        require(winner != address(0), "INVALID_WINNER");
        require(amount > 0, "INVALID_AMOUNT");
        require(address(this).balance >= amount, "INSUFFICIENT_POOL_BALANCE");

        usedPayoutIds[payoutId] = true;
        totalPaid += amount;

        payouts.push(
            TournamentPayout({
                payoutId: payoutId,
                tournamentId: tournamentId,
                winner: winner,
                amount: amount,
                paidAt: block.timestamp
            })
        );

        (bool success,) = winner.call{value: amount}("");
        require(success, "TRANSFER_FAILED");

        emit PrizePaid(tournamentId, payoutId, winner, amount);
    }
}

contracts/TaxForwarder.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

interface IForwarderRecoverableToken {
    function transfer(address to, uint256 value) external returns (bool);
}

contract TaxForwarder {
    uint256 public constant PRIZE_POOL_SHARE_NUMERATOR = 5;
    uint256 public constant PRIZE_POOL_SHARE_DENOMINATOR = 6;

    address public owner;
    address public marketingWallet;
    address public prizePool;
    bool public paused;

    mapping(address => bool) public pausers;

    event OwnerUpdated(address indexed previousOwner, address indexed newOwner);
    event MarketingWalletUpdated(address indexed previousWallet, address indexed newWallet);
    event PrizePoolUpdated(address indexed previousPrizePool, address indexed newPrizePool);
    event PauserUpdated(address indexed account, bool allowed);
    event Paused(address indexed account);
    event Unpaused(address indexed account);
    event TaxReceived(address indexed sender, uint256 amount, uint256 balanceAfter);
    event TaxForwarded(
        address indexed triggeredBy,
        uint256 totalAmount,
        uint256 prizePoolAmount,
        uint256 marketingAmount
    );
    event EmergencyNativeWithdrawn(address indexed recipient, uint256 amount);
    event EmergencyTokenWithdrawn(address indexed token, address indexed recipient, uint256 amount);

    modifier onlyOwner() {
        require(msg.sender == owner, "ONLY_OWNER");
        _;
    }

    modifier onlyPauser() {
        require(msg.sender == owner || pausers[msg.sender], "ONLY_PAUSER");
        _;
    }

    modifier whenNotPaused() {
        require(!paused, "FORWARDER_PAUSED");
        _;
    }

    modifier whenPaused() {
        require(paused, "FORWARDER_NOT_PAUSED");
        _;
    }

    constructor(address initialOwner, address initialMarketingWallet) {
        require(initialOwner != address(0), "INVALID_OWNER");
        require(initialMarketingWallet != address(0), "INVALID_MARKETING_WALLET");

        owner = initialOwner;
        marketingWallet = initialMarketingWallet;
        pausers[initialOwner] = true;

        emit PauserUpdated(initialOwner, true);
    }

    receive() external payable {
        emit TaxReceived(msg.sender, msg.value, address(this).balance);
    }

    function setOwner(address newOwner) external onlyOwner {
        require(newOwner != address(0), "INVALID_OWNER");
        emit OwnerUpdated(owner, newOwner);
        owner = newOwner;
    }

    function setMarketingWallet(address newMarketingWallet) external onlyOwner {
        require(newMarketingWallet != address(0), "INVALID_MARKETING_WALLET");
        emit MarketingWalletUpdated(marketingWallet, newMarketingWallet);
        marketingWallet = newMarketingWallet;
    }

    function setPrizePool(address newPrizePool) external onlyOwner {
        require(newPrizePool != address(0), "INVALID_PRIZE_POOL");
        emit PrizePoolUpdated(prizePool, newPrizePool);
        prizePool = newPrizePool;
    }

    function setPauser(address account, bool allowed) external onlyOwner {
        pausers[account] = allowed;
        emit PauserUpdated(account, allowed);
    }

    function pause() external onlyPauser {
        paused = true;
        emit Paused(msg.sender);
    }

    function unpause() external onlyPauser {
        paused = false;
        emit Unpaused(msg.sender);
    }

    function forward() external whenNotPaused {
        _forwardAvailableBalance();
    }

    function forwardableBalance() external view returns (uint256) {
        return address(this).balance;
    }

    function previewForwardAmounts() external view returns (uint256 prizePoolAmount, uint256 marketingAmount) {
        return _splitBalance(address(this).balance);
    }

    function emergencyWithdrawNative(address payable recipient, uint256 amount) external onlyOwner whenPaused {
        require(recipient != address(0), "INVALID_RECIPIENT");
        require(amount > 0, "INVALID_AMOUNT");
        require(address(this).balance >= amount, "INSUFFICIENT_NATIVE_BALANCE");

        (bool success,) = recipient.call{value: amount}("");
        require(success, "TRANSFER_FAILED");

        emit EmergencyNativeWithdrawn(recipient, amount);
    }

    function emergencyWithdrawUnexpectedToken(address token, address recipient, uint256 amount)
        external
        onlyOwner
        whenPaused
    {
        require(token != address(0), "INVALID_TOKEN");
        require(recipient != address(0), "INVALID_RECIPIENT");
        require(amount > 0, "INVALID_AMOUNT");

        bool success = IForwarderRecoverableToken(token).transfer(recipient, amount);
        require(success, "TRANSFER_FAILED");

        emit EmergencyTokenWithdrawn(token, recipient, amount);
    }

    function _forwardAvailableBalance() internal {
        require(prizePool != address(0), "PRIZE_POOL_NOT_SET");

        uint256 totalAmount = address(this).balance;
        require(totalAmount > 0, "NO_FUNDS_TO_FORWARD");

        (uint256 prizePoolAmount, uint256 marketingAmount) = _splitBalance(totalAmount);

        (bool prizePoolSuccess,) = payable(prizePool).call{value: prizePoolAmount}("");
        require(prizePoolSuccess, "PRIZE_POOL_TRANSFER_FAILED");

        (bool marketingSuccess,) = payable(marketingWallet).call{value: marketingAmount}("");
        require(marketingSuccess, "MARKETING_TRANSFER_FAILED");

        emit TaxForwarded(msg.sender, totalAmount, prizePoolAmount, marketingAmount);
    }

    function _splitBalance(uint256 amount) internal pure returns (uint256 prizePoolAmount, uint256 marketingAmount) {
        prizePoolAmount = (amount * PRIZE_POOL_SHARE_NUMERATOR) / PRIZE_POOL_SHARE_DENOMINATOR;
        marketingAmount = amount - prizePoolAmount;
    }
}

